// Convert the latest meter snapshot from flow context into a full register
// block, then push it into the modbus-server's holding-register space.
// Mirrors src/simulators/energy_meter/{register_map,ieee754}.py.

const REGISTER_ADDRESSES = {
    active_power_l1_w: 19000,
    active_power_l2_w: 19002,
    active_power_l3_w: 19004,
    active_power_total_w: 19006,
    voltage_l1_v: 19020,
    voltage_l2_v: 19022,
    voltage_l3_v: 19024,
    current_l1_a: 19040,
    current_l2_a: 19042,
    current_l3_a: 19044,
    power_factor: 19060,
    total_energy_kwh: 19062,
    frequency_hz: 19064
};

function float32ToRegisters(value) {
    const buf = Buffer.alloc(4);
    buf.writeFloatBE(value, 0);
    return [buf.readUInt16BE(0), buf.readUInt16BE(2)];
}

const meters = flow.get('latest_meters') || [];
if (meters.length === 0) {
    return null;
}

const meterIndex = Number(env.get('METER_INDEX') || 0);
const meter = meters[meterIndex] || meters[0];
if (!meter || !meter.readings) {
    return null;
}

const r = meter.readings;
const phases = [r.active_power_l1_w, r.active_power_l2_w, r.active_power_l3_w];
const allPhasesPresent = phases.every((v) => typeof v === 'number' && !Number.isNaN(v));
const totalActiveW = allPhasesPresent ? phases.reduce((a, b) => a + b, 0) : undefined;

const valueMap = {
    [REGISTER_ADDRESSES.active_power_l1_w]: r.active_power_l1_w,
    [REGISTER_ADDRESSES.active_power_l2_w]: r.active_power_l2_w,
    [REGISTER_ADDRESSES.active_power_l3_w]: r.active_power_l3_w,
    [REGISTER_ADDRESSES.active_power_total_w]: totalActiveW,
    [REGISTER_ADDRESSES.voltage_l1_v]: r.voltage_l1_v,
    [REGISTER_ADDRESSES.voltage_l2_v]: r.voltage_l2_v,
    [REGISTER_ADDRESSES.voltage_l3_v]: r.voltage_l3_v,
    [REGISTER_ADDRESSES.current_l1_a]: r.current_l1_a,
    [REGISTER_ADDRESSES.current_l2_a]: r.current_l2_a,
    [REGISTER_ADDRESSES.current_l3_a]: r.current_l3_a,
    [REGISTER_ADDRESSES.power_factor]: r.power_factor,
    [REGISTER_ADDRESSES.total_energy_kwh]: r.total_energy_kwh,
    [REGISTER_ADDRESSES.frequency_hz]: r.frequency_hz
};

const writes = [];
for (const [addrStr, value] of Object.entries(valueMap)) {
    if (typeof value !== 'number' || Number.isNaN(value)) continue;
    const addr = Number(addrStr);
    const [high, low] = float32ToRegisters(value);
    writes.push({ payload: { value: high, register: addr, fc: 'FC6' } });
    writes.push({ payload: { value: low, register: addr + 1, fc: 'FC6' } });
}

flow.set('modbus_last_write_count', writes.length);
flow.set('modbus_last_write_meter', meter.meter_id);

node.send([writes]);
return null;
